package backend

import "errors"

// ErrNotAvailable is returned when no keyring backend is available on the platform.
var ErrNotAvailable = errors.New("keyring backend not available")

// ErrNotImplemented is returned when a feature is not yet implemented.
var ErrNotImplemented = errors.New("not implemented yet")

//go:build darwin

package backend

import (
	"github.com/99designs/keychain"
)

const (
	kcService = "envmoat"
	kcKey     = "envmoat-luk"
)

// darwinKeyringBackend stores the LUK in the macOS Keychain via 99designs/keychain.
type darwinKeyringBackend struct{}

// StoreLUK stores the Local Unwrap Key in the macOS Keychain.
func (d *darwinKeyringBackend) StoreLUK(key []byte) error {
	kc, err := keychain.OpenMac(keychain.Name("envmoat"))
	if err != nil {
		return err
	}
	return kc.Set(keychain.Item{
		Class:       keychain.ClassGenericPassword,
		Service:     kcService,
		Account:     kcKey,
		Data:        key,
		WritableOnLoginKeychain: true,
	})
}

// GetLUK retrieves the Local Unwrap Key from the macOS Keychain.
// Returns ErrNotAvailable if no key is stored.
func (d *darwinKeyringBackend) GetLUK() ([]byte, error) {
	kc, err := keychain.OpenMac(keychain.Name("envmoat"))
	if err != nil {
		return nil, err
	}
	item, err := kc.Get(keychain.ClassGenericPassword, kcService, kcKey)
	if err != nil {
		return nil, ErrNotAvailable
	}
	return item.Data, nil
}

// DeleteLUK removes the Local Unwrap Key from the macOS Keychain.
func (d *darwinKeyringBackend) DeleteLUK() error {
	kc, err := keychain.OpenMac(keychain.Name("envmoat"))
	if err != nil {
		return err
	}
	return kc.Remove(keychain.ClassGenericPassword, kcService, kcKey)
}

func NewKeyringBackend() KeyringBackend {
	return &darwinKeyringBackend{}
}

